class Solution:
    def distanceBetweenBusStops(self, distance, start, destination):
        n = len(distance)
        a, b = start, destination
        cw = 0
        i = a
        while i != b:
            cw += distance[i]
            i = (i + 1) % n
        ccw = 0
        i = b
        while i != a:
            ccw += distance[i]
            i = (i + 1) % n
        return min(cw, ccw)

